    CALL UART_PUTS(ADDR(MSG));
END;

/* With parameters and return type */
ADD: PROC(A INT, B INT) RETURNS(INT);
    RETURN(A + B);
END;

/* Call as expression (without CALL keyword) */
RESULT = ADD(3, 4);

/* Call as statement */
CALL UART_PUTS(ADDR(MSG));

/* Naked procedure (no prologue/epilogue) */
ISR: PROC OPTIONS(NAKED);
    ASM DO;
        'push    r0';
        'pop     r0';
        'jmp     (iv)';
    END;
END;
```

