1	/* layout.h -- Storage layout computation for PL/SW compiler */
2	/* Walks DCL AST nodes to assign offsets, compute sizes, build type descriptors */
3	
4	#ifndef LAYOUT_H
5	#define LAYOUT_H
6	
7	#include "ast.h"
8	#include "symtab.h"
9	#include "types.h"
10	
11	/* --- Static address allocation --- */
12	
13	/* Base address for static variables in .data section */
14	#define STATIC_BASE 0x1000
15	
16	int layout_static_next;  /* next available static address */
17	
18	/* --- Frame layout state --- */
19	
20	int layout_frame_size;   /* total frame size for current procedure */
21	
22	/* --- Last allocated type descriptor (set by layout_dcl_width for records) --- */
23	int layout_last_tdesc;
24	
25	/* --- Layout error state --- */
26	
27	int layout_err;
28	char *layout_errmsg;
29	
30	void layout_init(void) {
31	    layout_static_next = STATIC_BASE;
32	    layout_frame_size = 0;
33	    layout_last_tdesc = -1;
34	    layout_err = 0;
35	    layout_errmsg = 0;
36	}
37	
38	void layout_error(char *msg) {
39	    layout_err = 1;
40	    layout_errmsg = msg;
41	}
42	
43	/* --- Compute the width of a DCL node --- */
44	/* Handles simple types, arrays, and records.
45	   For records, also builds a type descriptor.
46	   Returns the total width in bytes. */
47	
48	int layout_dcl_width(int node) {
49	    int w;
50	    int child;
51	    int fcount;
52	    int offset;
53	    int fw;
54	    int desc;
55	    int fbase;
56	
57	    if (node == NODE_NULL) return 0;
58	
59	    /* Record type: walk children to compute total size */
60	    if (nd_type[node] == TYPE_RECORD) {
61	        layout_last_tdesc = -1;
62	        offset = 0;
63	        fcount = 0;
64	
65	        /* Allocate a type descriptor for this record */
66	        desc = td_alloc(TDESC_RECORD);
67	        if (desc >= 0) {
68	            fbase = desc * TDESC_FIELD_MAX;
69	
70	            child = nd_left[node];
71	            while (child != NODE_NULL && fcount < TDESC_FIELD_MAX) {
72	                fw = layout_dcl_width(child);
73	                if (fw == 0) fw = 3;  /* default to 24-bit */
74	
75	                td_fname[fbase + fcount] = nd_name[child];
76	                td_ftype[fbase + fcount] = nd_type[child];
77	                td_fwidth[fbase + fcount] = fw;
78	                td_foffset[fbase + fcount] = offset;
79	
80	                offset = offset + fw;
81	                fcount = fcount + 1;
82	                child = nd_next[child];
83	            }
84	
85	            td_count[desc] = fcount;
86	            td_size[desc] = offset;
87	            layout_last_tdesc = desc;
88	        }
89	        return offset;
90	    }
91	
92	    /* Simple type width */
93	    w = type_width(nd_type[node]);
94	    if (w == 0) w = 3;  /* default to 24-bit for untyped */
95	
96	    /* Array: width = element_width * dimension */
97	    if (nd_ival[node] > 0) {
98	        w = w * nd_ival[node];
99	    }
100	
101	    return w;
102	}
