680	 * For NODE_ARRAY_ACCESS: nd_name = array name, nd_left = index expression.
681	 * Returns the element width (1 or 3) for load/store sizing, or 0 on error. */
682	
683	int cg_array_addr(int node) {
684	    int sym_idx;
685	    int elem_w;
686	    int arr_off;
687	
688	    sym_idx = sym_lookup(nd_name[node]);
689	    if (sym_idx < 0) {
690	        cg_error("undefined array variable");
691	        emit_comment("ERROR: undefined array variable");
692	        return 0;
693	    }
694	
695	    if (!(sym_flags[sym_idx] & SYM_F_ARRAY)) {
696	        cg_error("subscript on non-array variable");
697	        emit_comment("ERROR: not an array");
698	        return 0;
699	    }
700	
701	    /* Element width from the base type */
702	    elem_w = type_width(sym_type[sym_idx]);
703	    if (elem_w == 0) elem_w = 3;
704	
705	    arr_off = sym_offset[sym_idx];
706	
707	    /* Evaluate index expression into r0 */
708	    cg_expr(nd_left[node]);
709	
710	    /* Compute element offset: r0 = index * elem_w */
711	    if (elem_w == 3) {
712	        /* Multiply index by 3: r0 = r0 + r0 + r0 */
713	        emit_instr("mov     r1,r0");
714	        emit_instr("add     r0,r1");
715	        emit_instr("add     r0,r1");
716	    }
717	    /* elem_w == 1: no multiply needed, offset = index */
718	    /* elem_w == 2 would need shl by 1, but not common */
719	
720	    /* r0 = element byte offset. Compute base + offset into r2. */
721	    emit_instr("mov     r2,r0");
722	
723	    if (sym_stor[sym_idx] == STOR_STATIC || sym_stor[sym_idx] == STOR_EXTERNAL) {
724	        /* Static: r2 = r2 + label address */
725	        emit_str(EMIT_INDENT);
726	        emit_str("la      r0,_");
727	        emit_str(sym_name[sym_idx]);
728	        emit_nl();
729	        emit_instr("add     r2,r0");
730	    } else {
731	        /* Automatic: r2 = r2 + fp + stack_offset */
732	        if (arr_off >= -128 && arr_off <= 127) {
733	            emit_str(EMIT_INDENT);
734	            emit_str("lc      r0,");
735	            emit_int(arr_off);
736	            emit_nl();
737	        } else {
738	            emit_str(EMIT_INDENT);
739	            emit_str("la      r0,");
740	            emit_int(arr_off);
741	            emit_nl();
742	        }
743	        emit_instr("add     r2,r0");
744	        emit_instr("add     r2,fp");
745	    }
746	
747	    return elem_w;
748	}
749	
750	/* Load an array element value into r0 */
751	void cg_array_load(int node) {
752	    int ew;
753	    ew = cg_array_addr(node);
754	    if (ew == 0) return;
755	
756	    if (ew == 1) {
757	        emit_instr("lbu     r0,0(r2)");
758	    } else {
759	        emit_instr("lw      r0,0(r2)");
760	    }
761	}
762	
763	/* Store r0 into an array element.
764	 * Saves r0 on stack while computing address, then restores and stores. */
765	void cg_array_store(int node) {
766	    int ew;
767	
768	    emit_instr("push    r0");
769	    ew = cg_array_addr(node);
770	    emit_instr("pop     r0");
771	
772	    if (ew == 0) return;
773	
774	    if (ew == 1) {
775	        emit_instr("sb      r0,0(r2)");
776	    } else {
777	        emit_instr("sw      r0,0(r2)");
778	    }
779	}
780	
781	/* --- ADDR (address-of) codegen --- */
782	
783	/* Compute the address of a variable into r0.
784	 * For NODE_ADDR: nd_left = operand (NODE_IDENT, NODE_FIELD_ACCESS, or NODE_ARRAY_ACCESS).
785	 * Stack variables: fp + offset. Static: absolute address. */
786	
787	void cg_addr(int node) {
788	    int operand;
789	    int idx;
790	    int off;
791	
792	    operand = nd_left[node];
793	    if (operand == NODE_NULL) {
794	        cg_error("ADDR with no operand");
795	        emit_comment("ERROR: ADDR with no operand");
796	        emit_instr("lc      r0,0");
797	        return;
798	    }
